const cfg = $input.item.json;

const BASE = "https://api.afriquecod.com/api";
const ORIGIN = "https://manager.afriquecod.com";
const SUPABASE_URL = cfg.supabase_url;
const SUPABASE_SERVICE_ROLE_KEY = cfg.supabase_service_role_key;
const PER_PAGE = 100;
const UPSERT_BATCH_SIZE = 500;
const PAGE_DELAY_MS = 400; // petite pause entre pages pour rester sous la limite Cloudflare (~120 req)

const USER_AGENT =
  "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36";

const COUNTRIES = [
  {
    id: 17,
    old_id: "65dfdf15de9227002ef02de4",
    name: "Congo",
    currency: "XAF",
    currency_exchange_rate: 1,
    flag: "CG",
    phone_code: null,
    timezone: "Africa/Brazzaville",
    created_at: "2024-06-29T12:44:04.000000Z",
    updated_at: "2024-06-29T12:44:04.000000Z",
    deleted_at: null,
  },
];

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function bodyPreview(body) {
  try {
    return JSON.stringify(body).slice(0, 500);
  } catch {
    return String(body).slice(0, 500);
  }
}

async function africodLogin() {
  const res = await this.helpers.httpRequest({
    method: "POST",
    url: `${BASE}/login`,
    headers: {
      "Content-Type": "application/json",
      Accept: "application/json",
      "User-Agent": USER_AGENT,
      Origin: ORIGIN,
      Referer: `${ORIGIN}/`,
    },
    body: { email: cfg.africod_congo_email, password: cfg.africod_congo_password },
    json: true,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });

  if (res.statusCode < 200 || res.statusCode >= 300) {
    throw new Error(`POST /login → HTTP ${res.statusCode}: ${bodyPreview(res.body)}`);
  }

  const token = res.body && res.body.token;
  if (!token) {
    throw new Error(`POST /login → 200 mais pas de champ token: ${bodyPreview(res.body)}`);
  }
  return token;
}

// Retry avec backoff sur 403/429 (Cloudflare / rate limit) — jusqu'à 3 tentatives.
async function fetchShipmentsPage(token, country, page) {
  let attempt = 0;

  while (true) {
    const res = await this.helpers.httpRequest({
      method: "GET",
      url: `${BASE}/product-shipments`,
      qs: { per_page: PER_PAGE, page },
      headers: {
        Authorization: `Bearer ${token}`,
        Accept: "application/json",
        "User-Agent": USER_AGENT,
        "X-Selected-Country": JSON.stringify(country),
        Origin: ORIGIN,
        Referer: `${ORIGIN}/`,
      },
      json: true,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    });

    if (res.statusCode === 403 || res.statusCode === 429) {
      attempt += 1;
      if (attempt > 3) {
        throw new Error(`GET /product-shipments (page ${page}) → HTTP ${res.statusCode} après 3 tentatives: ${bodyPreview(res.body)}`);
      }
      await sleep(1500 * attempt);
      continue;
    }

    if (res.statusCode < 200 || res.statusCode >= 300) {
      throw new Error(`GET /product-shipments (page ${page}) → HTTP ${res.statusCode}: ${bodyPreview(res.body)}`);
    }

    return res.body;
  }
}

const allRows = [];
const errors = [];
const perCountry = [];

if (!cfg.africod_congo_email || !cfg.africod_congo_password) {
  errors.push({ country: "ALL", message: "africod_congo_email / africod_congo_password manquants dans le nœud 'Config'." });
} else {
  let token = null;

  try {
    token = await africodLogin.call(this);
  } catch (err) {
    errors.push({ country: "ALL", message: `Login initial échoué — ${err.message}` });
  }

  if (token) {
    for (const country of COUNTRIES) {
      let fetched = 0;
      let apiTotal = null;

      try {
        let page = 1;
        let lastPage = 1;

        do {
          const data = await fetchShipmentsPage.call(this, token, country, page);
          const pagination = data.pagination || {};
          lastPage = pagination.last_page ?? 1;
          if (apiTotal === null) apiTotal = pagination.total ?? null;

          for (const s of data.productShipments || []) {
            const countryName = s.warehouse?.country?.name ?? country.name;

            for (const item of s.shipment_items || []) {
              allRows.push({
                item_id: item.id,
                shipment_id: s.id,
                country: countryName,
                product_name: item.product?.name ?? "Inconnu",
                shipment_date: s.shipment_date ?? null,
                arrival_date: s.arrival_date ?? null,
                source_country: s.source_country ?? null,
                quantity_sent: item.quantity_sent ?? null,
                quantity_arrived: item.quantity_arrived ?? null,
                quantity_defected: item.quantity_defected ?? null,
                status: s.shipment_status ?? null,
              });
              fetched += 1;
            }
          }

          page += 1;
          if (page <= lastPage) await sleep(PAGE_DELAY_MS);
        } while (page <= lastPage);
      } catch (err) {
        errors.push({ country: country.name, message: err.message });
      }

      perCountry.push({ country: country.name, apiTotal, fetched });
    }
  }
}

// ─── Upsert en masse vers Supabase, par lots de 500 lignes ─────────────
const dedupedRows = Array.from(new Map(allRows.map((r) => [r.item_id, r])).values());

let upserted = 0;

for (let i = 0; i < dedupedRows.length; i += UPSERT_BATCH_SIZE) {
  const batch = dedupedRows.slice(i, i + UPSERT_BATCH_SIZE);

  try {
    const res = await this.helpers.httpRequest({
      method: "POST",
      url: `${SUPABASE_URL}/rest/v1/africod_congo_shipments`,
      headers: {
        "Content-Type": "application/json",
        apikey: SUPABASE_SERVICE_ROLE_KEY,
        Authorization: `Bearer ${SUPABASE_SERVICE_ROLE_KEY}`,
        Prefer: "resolution=merge-duplicates,return=minimal",
      },
      body: batch,
      json: true,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    });

    if (res.statusCode < 200 || res.statusCode >= 300) {
      throw new Error(`HTTP ${res.statusCode}: ${bodyPreview(res.body)}`);
    }

    upserted += batch.length;
  } catch (err) {
    errors.push({ country: "SUPABASE_UPSERT", message: `lot ${i}-${i + batch.length}: ${err.message}` });
  }
}

return [
  {
    json: {
      synced_items: upserted,
      countries: COUNTRIES.map((c) => c.name),
      perCountry,
      errors,
      finished_at: new Date().toISOString(),
    },
  },
];
